var maximumSetSize = function(nums1, nums2) {
    const n = nums1.length;
    const half = Math.floor(n / 2);
    const s1 = new Set(nums1);
    const s2 = new Set(nums2);
    let only1 = 0, only2 = 0, common = 0;
    for (const v of s1) { if (s2.has(v)) common++; else only1++; }
    for (const v of s2) { if (!s1.has(v)) only2++; }
    const take1 = Math.min(only1, half);
    const take2 = Math.min(only2, half);
    const rem1 = half - take1;
    const rem2 = half - take2;
    const shared = Math.min(common, rem1 + rem2);
    return take1 + take2 + shared;
};
